cd $SANDBOX && cat > zz_gt_test.go <<'EOF'
package parser
import ("reflect"; "testing")
func TestGTSplit(t *testing.T) {
	if got := SplitFields("a, b, c"); !reflect.DeepEqual(got, []string{"a","b","c"}) { t.Fatalf("basic=%#v", got) }
	if got := SplitFields("a,,b,"); !reflect.DeepEqual(got, []string{"a","b"}) { t.Fatalf("holes=%#v", got) }
	if got := SplitFields("  x  ,  y  "); !reflect.DeepEqual(got, []string{"x","y"}) { t.Fatalf("trim=%#v", got) }
	if got := SplitFields(""); got == nil || len(got) != 0 { t.Fatalf("empty must be non-nil len0, got %#v", got) }
	if got := SplitFields("   "); got == nil || len(got) != 0 { t.Fatalf("ws must be non-nil len0, got %#v", got) }
	if got := SplitFields(",,,"); got == nil || len(got) != 0 { t.Fatalf("commas-only must be non-nil len0, got %#v", got) }
}
EOF
go test ./... && rm -f zz_gt_test.go
